import 'dart:async';import 'package:bot_toast/bot_toast.dart';import 'package:flutter/cupertino.dart';import 'package:flutter/foundation.dart';import 'package:flutter/gestures.dart';import 'package:flutter/material.dart';import 'package:get/get.dart';import 'package:webview_flutter/webview_flutter.dart';import '../../core/constants/app_info.dart';class PrivacyPage extends StatefulWidget {  const PrivacyPage({super.key});  @override  State<PrivacyPage> createState() => _PrivacyPageState();}class _PrivacyPageState extends State<PrivacyPage> with WidgetsBindingObserver{  WebViewController _controller = WebViewController();  late DragGesturePullToRefresh dragGesturePullToRefresh; // Here  double _progress = 0;  @override  void initState() {    dragGesturePullToRefresh = DragGesturePullToRefresh(); // Here    _controller = WebViewController()      ..setJavaScriptMode(JavaScriptMode.unrestricted)      ..enableZoom(true)      ..setNavigationDelegate(        NavigationDelegate(          onProgress: (int progress) {            setState(() {              _progress = progress / 100; // Convert to a value between 0 and 1            });          },          onPageStarted: (String url) {            // Don't allow RefreshIndicator if page is loading, but not needed            dragGesturePullToRefresh.started(); // Here          },          onPageFinished: (String url) {            // Hide RefreshIndicator for page reload if showing            dragGesturePullToRefresh.finished(); // Here          },          onWebResourceError: (WebResourceError error) {            //debugPrint('MyWebViewWidget:onWebResourceError(): ${error.description}');            // Hide RefreshIndicator for page reload if showing            dragGesturePullToRefresh.finished(); // Here          },        ),      )      ..loadRequest(Uri.parse(AppInfo.privacyPolicy));    dragGesturePullToRefresh // Here        .setController(_controller)        .setDragHeightEnd(200)        .setDragStartYDiff(10)        .setWaitToRestart(3000);    //setState(() {});    WidgetsBinding.instance.addObserver(this);    super.initState();  }  @override  void dispose() {    // remove listener    WidgetsBinding.instance.removeObserver(this);    super.dispose();  }  @override  Widget build(BuildContext context) {    return Scaffold(      appBar: AppBar(title: Text('privacy_policy'.tr)),      body: Column(        children: [          LinearProgressIndicator(            value: _progress,            minHeight: 3, // Adjust height as needed            backgroundColor: Colors.grey[300], // Customize background            valueColor: const AlwaysStoppedAnimation<Color>(Colors.blue), // Customize progress color          ),          Expanded(child: RefreshIndicator(            triggerMode: RefreshIndicatorTriggerMode.onEdge,            onRefresh: dragGesturePullToRefresh.refresh, // Here            child: Builder(              builder: (context) {                // IMPORTANT: Use the RefreshIndicator context!                dragGesturePullToRefresh.setContext(context); // Here                return WebViewWidget(                  controller: _controller,                  // Add it to the WebViewWidget                  gestureRecognizers: {Factory(() => dragGesturePullToRefresh)}, // Here                );              },            ),          ))        ],      ),    );  }}class DragGesturePullToRefresh extends VerticalDragGestureRecognizer {  static const int exceedsLoadingTime = 3000;  late BuildContext _context;  late WebViewController _controller;  // loading  Completer<void> completer = Completer<void>();  late int msWaitToRestart;  int  msLoading = 0;  bool isLoading = true;  // drag  int    dragStartYDiff = 0;  double dragHeightEnd = 200;  bool   dragStarted = false;  double dragDistance = 0;  @override  //override rejectGesture here  void rejectGesture(int pointer) {    acceptGesture(pointer);  }  void _clearDrag() {    dragStarted = false;    dragDistance = 0;  }  /// [context] RefreshIndicator  DragGesturePullToRefresh setContext(BuildContext context) { _context = context; return this; }  /// [controller] WebViewController  DragGesturePullToRefresh setController(WebViewController controller) { _controller = controller; return this; }  /// [dragHeightEnd] End height for starting the refresh  DragGesturePullToRefresh setDragHeightEnd(double value)      { dragHeightEnd = value;   return this; }  /// [msWaitToRestart] milliseconds to reallow pull to refresh if the website  /// didn't load in msWaitToRestart time  DragGesturePullToRefresh setWaitToRestart(int value)  { msWaitToRestart = value; return this; }  /// [dragStartYDiff] add some offset as page top is not always obviously page top, e.g. 10  DragGesturePullToRefresh setDragStartYDiff(int value) { dragStartYDiff = value;  return this; }  /// start refresh  Future<void> refresh() {    if (!completer.isCompleted) {      completer.complete();    }    completer = Completer<void>();    started();    _controller.reload();    return completer.future;  }  /// Loading started  void started() {    msLoading = DateTime.now().millisecondsSinceEpoch;    isLoading = true;  }  /// Loading finished  void finished() {    msLoading = 0;    isLoading = false;    // hide the RefreshIndicator    if (!completer.isCompleted) {      completer.complete();    }  }  FixedScrollMetrics _getMetrics(double minScrollExtent, double maxScrollExtent,      double pixels, double viewportDimension, AxisDirection axisDirection) {    return FixedScrollMetrics(        minScrollExtent: minScrollExtent,        maxScrollExtent: maxScrollExtent,        pixels: pixels,        viewportDimension: viewportDimension,        axisDirection: axisDirection, devicePixelRatio: 1    );  }  /// [msWaitToRestart] milliseconds to reallow pull to refresh if the website  /// didn't load in msWaitToRestart time  ///  /// [dragStartYDiff] add some offset as page top is not always obviously page top, e.g. 10  DragGesturePullToRefresh([this.msWaitToRestart = exceedsLoadingTime, this.dragStartYDiff = 0]) {    onStart = (DragStartDetails dragDetails) async {      //debugPrint('DragGesturePullToRefresh(): $dragDetails');      if (!isLoading ||          // Reallow pull to refresh if the website didn't load in msWaitToRestart time          (msLoading > 0 && (DateTime.now().millisecondsSinceEpoch - msLoading) > msWaitToRestart)) {        Offset scrollPos = await _controller.getScrollPosition();        // Only allow RefreshIndicator if you are at the top of page!        if (scrollPos.dy <= dragStartYDiff) {          dragStarted = true;          dragDistance = 0;          ScrollStartNotification(              metrics: _getMetrics(0, dragHeightEnd, 0, dragHeightEnd, AxisDirection.down),              dragDetails: dragDetails,              context: _context          ).dispatch(_context);        }      }    };    onUpdate = (DragUpdateDetails dragDetails) {      if (dragStarted) {        double dy = dragDetails.delta.dy;        dragDistance += dy;        ScrollUpdateNotification(            metrics: _getMetrics(                dy > 0 ? 0 : dragDistance, dragHeightEnd,                dy > 0 ? (-1) * dy : dragDistance, dragHeightEnd,                dragDistance < 0 ? AxisDirection.up : AxisDirection.down),            context: _context,            scrollDelta: (-1) * dy        ).dispatch(_context);        if (dragDistance < 0) {          _clearDrag();        }      }    };    onEnd = (DragEndDetails dragDetails) {      if (dragStarted) {        ScrollEndNotification(            metrics: _getMetrics(0, dragHeightEnd, dragDistance, dragHeightEnd, AxisDirection.down),            context: _context        ).dispatch(_context);        _clearDrag();      }    };    onCancel = () {      if (dragStarted) {        ScrollUpdateNotification(            metrics: _getMetrics(0, dragHeightEnd, 1, dragHeightEnd, AxisDirection.up),            context: _context,            scrollDelta: 0        ).dispatch(_context);        _clearDrag();      }    };  }}